+import { $internal } from '../common';
+import { trait } from '../trait/trait';
+import type { Trait, TraitRecord, TraitValue } from '../trait/types';
+
+export const $aspect = Symbol('aspect');
+
+export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: TTraits;
+    readonly schema: Record<string, unknown>;
+    /** @internal A private tag used to track complete aspect membership in a world. */
+    readonly marker: Trait;
+};
+
+export type AspectValue<T extends Aspect> = T extends Aspect<infer TTraits>
+    ? UnionToIntersection<TraitRecord<TTraits[number]>>
+    : never;
+export type AspectInput<T extends Aspect> = Partial<AspectValue<T>>;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return Boolean((value as Aspect | undefined)?.[$aspect]);
+}
+
+export function createAspect<const TTraits extends readonly [Trait, Trait, ...Trait[]]>(
+    ...inputs: TTraits
+): Aspect<FlattenTraits<TTraits>> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const schema: Record<string, unknown> = {};
+    const fields = new Set<string>();
+    for (const constituent of traits) {
+        if (constituent[$internal].relation) {
+            throw new Error('Koota: Relations cannot be constituents of an aspect.');
+        }
+        for (const field of Object.keys(constituent.schema)) {
+            if (fields.has(field)) {
+                throw new Error(`Koota: Aspect constituents cannot share the field "${field}".`);
+            }
+            fields.add(field);
+            schema[field] = (constituent.schema as Record<string, unknown>)[field];
+        }
+    }
+
+    return Object.freeze({
+        [$aspect]: true as const,
+        id: aspectId++,
+        traits: Object.freeze(traits) as FlattenTraits<TTraits>,
+        schema: Object.freeze(schema),
+        marker: trait(),
+    });
+}
+
+type FlattenTrait<T> = T extends Aspect<infer Traits> ? Traits[number] : T extends Trait ? T : never;
+type FlattenTraits<T extends readonly unknown[]> = { [K in keyof T]: FlattenTrait<T[K]> };
+type UnionToIntersection<T> = (T extends unknown ? (value: T) => void : never) extends (
+    value: infer Result
+) => void
+    ? Result
+    : never;
